PRAGMA foreign_keys = ON;
CREATE TABLE referral_accounts (id TEXT PRIMARY KEY, revenuecat_customer_id TEXT NOT NULL UNIQUE, identity_family_hash TEXT NOT NULL UNIQUE, lifetime_status INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE account_aliases (alias_hash TEXT PRIMARY KEY, account_id TEXT NOT NULL REFERENCES referral_accounts(id), created_at TEXT NOT NULL);
CREATE TABLE registered_devices (id TEXT PRIMARY KEY, account_id TEXT NOT NULL REFERENCES referral_accounts(id), public_key_jwk TEXT NOT NULL, key_version INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL, last_seen_at TEXT NOT NULL, revoked_at TEXT, UNIQUE(account_id, public_key_jwk));
CREATE TABLE request_nonces (device_id TEXT NOT NULL REFERENCES registered_devices(id), nonce TEXT NOT NULL, expires_at TEXT NOT NULL, PRIMARY KEY(device_id, nonce));
CREATE TABLE referral_codes (id TEXT PRIMARY KEY, sender_account_id TEXT NOT NULL REFERENCES referral_accounts(id), code_hash TEXT NOT NULL UNIQUE, display_code TEXT NOT NULL, display_suffix TEXT NOT NULL, created_at TEXT NOT NULL, revoked_at TEXT);
CREATE TABLE referrals (id TEXT PRIMARY KEY, sender_account_id TEXT NOT NULL REFERENCES referral_accounts(id), recipient_account_id TEXT NOT NULL REFERENCES referral_accounts(id), referral_code_id TEXT NOT NULL REFERENCES referral_codes(id), status TEXT NOT NULL CHECK(status IN ('claimed','offer_reserved','redeemed','rejected','expired')), claimed_at TEXT NOT NULL, redeemed_at TEXT, rejection_reason TEXT, UNIQUE(sender_account_id,recipient_account_id), UNIQUE(recipient_account_id));
CREATE TABLE credit_ledger (id TEXT PRIMARY KEY, account_id TEXT NOT NULL REFERENCES referral_accounts(id), referral_id TEXT REFERENCES referrals(id), redemption_id TEXT, entry_type TEXT NOT NULL CHECK(entry_type IN ('earned','reserved','reservation_released','consumed','reversed','admin_adjustment')), quantity INTEGER NOT NULL, idempotency_key TEXT NOT NULL UNIQUE, created_at TEXT NOT NULL);
CREATE INDEX credit_ledger_account ON credit_ledger(account_id,created_at);
CREATE TABLE redemptions (id TEXT PRIMARY KEY, account_id TEXT NOT NULL REFERENCES referral_accounts(id), referral_id TEXT REFERENCES referrals(id), credit_ledger_reservation_id TEXT REFERENCES credit_ledger(id), fulfillment_type TEXT NOT NULL CHECK(fulfillment_type IN ('offer_code','promotional_offer','manual_fallback')), configured_product TEXT NOT NULL CHECK(configured_product IN ('monthly','yearly')), apple_offer_reference TEXT, revenuecat_transaction_id TEXT UNIQUE, status TEXT NOT NULL CHECK(status IN ('reserved','presented','confirmed','failed','expired')), reserved_at TEXT NOT NULL, expires_at TEXT NOT NULL, confirmed_at TEXT, idempotency_key TEXT NOT NULL UNIQUE);
CREATE UNIQUE INDEX one_open_redemption ON redemptions(account_id) WHERE status IN ('reserved','presented');
CREATE TABLE offer_code_inventory (id TEXT PRIMARY KEY, offer_reference TEXT NOT NULL, encrypted_code TEXT NOT NULL, product TEXT NOT NULL, status TEXT NOT NULL CHECK(status IN ('available','reserved','assigned','redeemed','expired','invalid')), reservation_id TEXT REFERENCES redemptions(id), created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE webhook_events (id TEXT PRIMARY KEY, provider_event_id TEXT NOT NULL UNIQUE, event_type TEXT NOT NULL, payload_hash TEXT NOT NULL, processing_status TEXT NOT NULL, received_at TEXT NOT NULL, processed_at TEXT);
CREATE TABLE idempotency_responses (account_id TEXT NOT NULL, idempotency_key TEXT NOT NULL, request_hash TEXT NOT NULL, status INTEGER NOT NULL, response_json TEXT NOT NULL, created_at TEXT NOT NULL, PRIMARY KEY(account_id,idempotency_key));
CREATE TABLE abuse_signals (signal_hash TEXT NOT NULL, bucket TEXT NOT NULL, count INTEGER NOT NULL, expires_at TEXT NOT NULL, PRIMARY KEY(signal_hash,bucket));
